    static class TaskC {
        public void solve(int testNumber, MyInput in, PrintWriter out) {
            int n = in.nextInt();
            int r = in.nextInt();
            int[] x = in.nextIntArray(n);
            double[] py = new double[n];
            for (int i = 0; i < n; i++) {
                double y = r;
                for (int j = 0; j < i; j++) {
                    int dx = Math.abs(x[i] - x[j]);
                    if (dx > 2 * r) continue;
                    y = Math.max(y, Math.sqrt(4 * r * r - dx * dx) + py[j]);
                }
                py[i] = y;
            }
            for (int i = 0; i < n; i++) {
                out.printf("%.10f%s", py[i], i == n - 1 ? "\n" : " ");
            }
