			lines[i] = next();
		}
		int mod = 1000000000 + 7;

		long[][] dp = new long[2][n + 1];
		dp[0][0] = 1;
		for (int i = 0; i < n; i ++) {
			int from = i % 2;
			int to = (i + 1) % 2;
			boolean flg = i == 0 || lines[i - 1].equals("s");
			if (flg) {
				long v = Arrays.stream(dp[from]).sum();
				for (int j = 0; j <= n; j ++) {
					dp[to][j] += v;
					dp[to][j] %= mod;
					v -= dp[from][j];
				}
			} else {
				for (int j = 0; j < n; j ++) {
					dp[to][j + 1] += dp[from][j];
					dp[to][j + 1] %= mod;
				}
			}
