    static class TaskC {
        public int mod = (int) Math.pow(10, 9) + 7;

        public void solve(int testNumber, InputReader in, PrintWriter out) {
            // out.print("Case #" + testNumber + ": ");
            int n = in.readInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
