            int indent = 0;
            if (a[0] == 1) indent++;
            for (int i = 1; i < n; i++) {
                if (a[i - 1] == 1) {
                    for (int j = indent - 1; j >= 1; j--) {
                        ans[i][j] = ans[i - 1][j - 1];
                    }
                    ans[i][indent] = 1;
                } else {
                    for (int j = indent; j >= 0; j--) {
                        ans[i][j] = (ans[i][j + 1] + ans[i - 1][j]) % mod;
                    }
                }
                indent += a[i];
            }/*
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                out.print(ans[i][j]+" ");
            }
            out.println();
        }*/
            long aa = 0;
