    static int f(int idx, int b) {
        if(idx == l.size())
            return 1;
        if(dp[idx][b] != -1)
            return dp[idx][b];
        long ret = f(idx + 1, b + l.get(idx));
        if(b > 0)
            ret += f(idx, b - 1);
