				dp[i][j]=x%mod;
		}
		else {
			int x=-1;
			if(j!=0)
			x=ans(dp,i,j-1,a,n);
			int y=ans(dp,i+1,j,a,n);
			if(x!=-1)
				dp[i][j]=x%mod;
			if(y!=-1) {
				if(dp[i][j]==-1)
					dp[i][j]=y%mod;
				else
				dp[i][j]+=y%mod;}
		}
		return dp[i][j];
	}
}

