public class c {

	static boolean seq[];
	static long memo[][], mod = (long)1e9 + 7;
	static long go(int n, int d) {
		long ans = 0;
		if(d < 0) return 0;
		if(n == seq.length) return 1;
		int f = 1;
		if(n > 0) f = seq[n-1]?1:0;
		if(memo[n][d] != -1) return memo[n][d];
		if(f == 0) {
			ans += go(n + 1, d + (seq[n]?1:0));
			ans %= mod;
			ans += go(n, d-1);
			ans %= mod;
		}
		if(f == 1) {
			ans += go(n + 1, d + (seq[n]?1:0));
			ans %= mod;
		}
		return memo[n][d] = ans;
	}

