//        }
//        out.printLine(recur(0, 0));
        }

        public long iterative() {
            int i, j, N = a.length, lastLevel = 0;
            dp[0][0] = 1;
            for (i = 1; i < N; i++) {
                if (a[i - 1] == 1) {
                    lastLevel++;
                    for (j = 1; j <= lastLevel; j++) {
                        dp[i][j] = dp[i - 1][j - 1];
                    }
                } else {
                    dp[i][N - 1] = dp[i - 1][N - 1];
                    for (j = N - 2; j >= 0; j--) {
                        dp[i][j] = (dp[i][j + 1] + dp[i - 1][j]) % MOD;
                    }
                }
            }
            long ans = 0;
            for (i = 0; i < N; i++) {
                ans += dp[N - 1][i];
            }
            return ans % MOD;
        }

