					}
					lazy[node]=0;
				}

				if (start>=l&&end<=r)
					return tree[node];

				int mid=(start+end)>>1;
				return add(queryRangeSum(node*2, start, mid, l, r),queryRangeSum(node*2+1, mid+1, end, l, r));
			}
		}

