					sum=(sum+(memo[i-1][j]%mod))%mod;
					memo[i][j]=sum;
				}
			}
			else{
				k+=1;
				for(int j=1; j<=k; j++){
					memo[i][j] = memo[i-1][j-1] % mod;
				}
			}
		}
		//print(n, memo);
		long sum=0;
		for(int i=0;i<=k;i++){
			sum=(sum+(memo[n-1][i])%mod)%mod;
