public class Main {

	static PrintWriter out;
	static InputReader ir;

	static void solve() {
		int n=ir.nextInt();
		int[] a=ir.nextIntArray(n);
		int m=ir.nextInt();
		long ret=mergeSort(a,0,n)%2;
		int p,q;
		for(int i=0;i<m;i++){
			p=ir.nextInt()-1;
			q=ir.nextInt()-1;
			if((q-p)%4==1||(q-p)%4==2)
				ret^=1;
			f(ret);
		}
	}

	public static void f(long a){
		if(a==0){
			out.println("even");
		}
		else
			out.println("odd");
	}
	public static long mergeSort(int[] a, int left, int right) {
        long cnt = 0;
        if (left + 1 < right) {
            int mid = (left + right) / 2;
            cnt += mergeSort(a, left, mid);
            cnt += mergeSort(a, mid, right);
            cnt += merge(a, left, mid, right);
        }

        return cnt;
    }

    public static long merge(int[] a, int left, int mid, int right) {
        long cnt = 0;
        int n1 = mid - left;
        int n2 = right - mid;
        int[] l = new int[n1 + 1];
        int[] r = new int[n2 + 1];
        for (int i = 0; i < n1; i++) {
            l[i] = a[left + i];
        }
        for (int i = 0; i < n2; i++) {
            r[i] = a[mid + i];
        }
        l[n1] = Integer.MAX_VALUE;
        r[n2] = Integer.MAX_VALUE;

        for (int i = 0, j = 0, k = left; k < right; k++) {
