		int b[] = new int[n];
		int c[] = new int[m];
		for(i = 0; i < n; i++)	b[i] = a[s + i];
		for(j = 0; j < m; j++)	c[j] = a[mid + 1 + j];
		i = j = 0;
		int ans = 0;
		for(int k = s; k <= e; k++){
			if(i == n){
				a[k] = c[j++];
