	void solve()
	{
		int n = ni();
		int[] a = ia(n);
		int Q = ni();
		String[] ans = {"even", "odd"};
		int cur = merge(a, 0, n - 1) % 2;
		while(Q-->0)
		{
			int l = ni(), r = ni();
			cur ^= (r - l + 1) / 2 % 2;
			out.println(ans[cur]);
		}

	}

	int merge(int[] a, int l, int r)
	{
		if(l >= r)
			return 0;
		int mid = l + r >> 1;
		int v1 = merge(a, l, mid);
		int v2 = merge(a, mid + 1, r);

		int[] rep = new int[r-l+1];
		int ptr0 = 0, ptr1 = l, ptr2 = mid + 1;

		long len = mid-l+1;
		int ret = 0;
		while(ptr1<=mid && ptr2<=r)
		{
			if(a[ptr1] <= a[ptr2])
			{
				len--;
				rep[ptr0++] = a[ptr1++];
			}
			else
			{
				ret += len;
				rep[ptr0++] = a[ptr2++]; 
			}
		}

		while(ptr1 <= mid)
			rep[ptr0++] = a[ptr1++];
		while(ptr2 <= r)
			rep[ptr0++] = a[ptr2++];

		for(int i=0;i<ptr0;i++)
			a[l+i] = rep[i];

		return v1 + v2 + ret;
	}

