		int n = f.nextInt();
		int[] arr = new int[n];
		BIT = new int[n+10];
		int inv = 0;
		for(int i = 0; i < n; i++) {
			arr[i] = f.nextInt();
			inv ^= (i-query(arr[i])) & 1;
			add(arr[i]);
		}
		int k = f.nextInt();
		while(k-->0) {
			int diff = -f.nextInt()+f.nextInt()+1;
			inv ^= (diff*(diff-1)/2) & 1;
			out.println(inv == 1 ? "odd" : "even");
		}
		out.flush();
	}

	public int query(int i) {
		i++;
		int res = 0;
		while(i > 0) {
			res += BIT[i];
			i -= i & -i;
		}
		return res;
	}
	public void add(int i) {
		i++;
		while(i < BIT.length) {
			BIT[i]++;
			i += i & -i;
		}
	}



