    static class TaskD {
        public void solve(int testNumber, FastScanner in, PrintWriter out) {
            int n = in.nextInt();
            int[] arr = new int[n + 1];
            for (int i = 1; i <= n; i++) {
                arr[i] = in.nextInt();
            }
            int inversions = 0;
            for (int i = 1; i <= n; i++) {
                for (int j = i + 1; j <= n; j++) {
                    if (arr[i] > arr[j])
                        inversions++;
                }
            }
            inversions %= 2;
            int q = in.nextInt();
            for (int i = 0; i < q; i++) {
                int l = in.nextInt(), r = in.nextInt();
                int d = r - l + 1;
                d = d * (d - 1) / 2;
                if ((d & 1) == 1) inversions ^= 1;
                out.println((inversions & 1) == 1 ? "odd" : "even");
            }
        }

