                b = !b;
            }
            writer.println(b ? "odd" : "even");
        }
    }

        static class MyReader {

            final BufferedInputStream in;
            final int bufSize = 1 << 16;
            final byte buf[] = new byte[bufSize];
            int i = bufSize;
            int k = bufSize;
            boolean end = false;
            final StringBuilder str = new StringBuilder();

            MyReader(InputStream in) {
                this.in = new BufferedInputStream(in, bufSize);
            }

            int nextInt() throws IOException {
                return (int) nextLong();
            }

            int[] nextIntArray(int n) throws IOException {
                int[] m = new int[n];
                for (int i = 0; i < n; i++) {
                    m[i] = nextInt();
                }
                return m;
            }

            int[][] nextIntMatrix(int n, int m) throws IOException {
                int[][] a = new int[n][0];
                for (int j = 0; j < n; j++) {
                    a[j] = nextIntArray(m);
                }
                return a;
            }

            long nextLong() throws IOException {
                int c;
                long x = 0;
                boolean sign = true;
                while ((c = nextChar()) <= 32) ;
                if (c == '-') {
                    sign = false;
                    c = nextChar();
                }
                if (c == '+') {
                    c = nextChar();
                }
                while (c >= '0') {
                    x = x * 10 + (c - '0');
                    c = nextChar();
                }
                return sign ? x : -x;
            }

            long[] nextLongArray(int n) throws IOException {
                long[] m = new long[n];
                for (int i = 0; i < n; i++) {
                    m[i] = nextLong();
                }
                return m;
            }

            int nextChar() throws IOException {
                if (i == k) {
                    k = in.read(buf, 0, bufSize);
                    i = 0;
                }
                return i >= k ? -1 : buf[i++];
            }

            String nextString() throws IOException {
                if (end) {
                    return null;
                }
                str.setLength(0);
                int c;
                while ((c = nextChar()) <= 32 && c != -1) ;
                if (c == -1) {
                    end = true;
                    return null;
                }
                while (c > 32) {
                    str.append((char) c);
                    c = nextChar();
                }
                return str.toString();
            }

            String nextLine() throws IOException {
                if (end) {
                    return null;
                }
                str.setLength(0);
                int c = nextChar();
                while (c != '\n' && c != '\r' && c != -1) {
                    str.append((char) c);
                    c = nextChar();
                }
                if (c == -1) {
                    end = true;
                    if (str.length() == 0) {
                        return null;
                    }
                }
                if (c == '\r') {
                    nextChar();
                }
                return str.toString();
            }

            char[] nextCharArray() throws IOException {
                return nextString().toCharArray();
            }

            char[][] nextCharMatrix(int n) throws IOException {
                char[][] a = new char[n][0];
                for (int i = 0; i < n; i++) {
                    a[i] = nextCharArray();
                }
                return a;
            }
        }

        static class MyWriter {

