public class C915D implements Runnable {

    private void solve() throws Exception {
        int n = i(), m = i();
        List<Set<Integer>> a = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            a.add(new HashSet<>());
        }
        for (int i = 0; i < m; i++) {
            int u = i() - 1, v = i() - 1;
            a.get(u).add(v);
        }

        int[] cycle = getCycle(a);
        if (cycle==null) {
            System.out.println("YES");
            return;
        }

        boolean canBeAcyclyc = false;
        for (int i = 0; i < cycle.length; i++) {
            int u = cycle[i];
            int v;
            if (i < cycle.length - 1) {
                v = cycle[i + 1];
            } else {
                v = cycle[0];
            }

            a.get(u).remove(v);

            if (getCycle(a) == null) {
                canBeAcyclyc = true;
                break;
            }

            a.get(u).add(v);
        }

        if (canBeAcyclyc) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }
    }

    private int[] getCycle(List<Set<Integer>> a) {
        int n = a.size();
        boolean[] visited = new boolean[n];

        int[] cycle = null;
        for (int i = 0; i < n; i++) {
            Set<Integer> current = new HashSet<>();
            List<Integer> backtrack = new ArrayList<>();
            cycle = dfs(i, a, visited, current, backtrack);
            if (cycle != null) break;
        }
        return cycle;
    }

    int[] dfs(Integer e, List<Set<Integer>> a, boolean[] visited, Set<Integer> current, List<Integer> backtrack) {
        if (visited[e]) {
            if (current.contains(e)) {
                var result = new ArrayList<Integer>();
                for (int i = backtrack.indexOf(e); i < backtrack.size(); i++) {
                    result.add(backtrack.get(i));
                }
                return result.stream().mapToInt(i -> i).toArray();
            }
            return null;
        }

        visited[e] = true;
        current.add(e);
        backtrack.add(e);

        for (Integer v : a.get(e)) {
            int[] result = dfs(v, a, visited, current, backtrack);
            if (result != null)
                return result;
        }

        current.remove(e);
        backtrack.remove(backtrack.size() - 1);

        return null;
    }

    public void run() {
        long start = System.currentTimeMillis();

        try {
            solve();
        } catch (Exception e) {
            throw new RuntimeException(e);
        } finally {
            out.close();
        }

        if (!isOj)
            System.out.println(System.currentTimeMillis() - start + "ms");
    }

