            if(ind<s.length() && s.charAt(ind)=='1'){
                ans+=vals[i];
            }
        }
        long val= Long.parseLong(s,2);
       // System.out.println("val="+val);
        ans+=((val)/(power(2,x-1,(long)1e18)))*vals[0];
        return ans;











