	void solve()
	{
		int n = ni();
		int[] a = na(2*n);
		int[] b = Arrays.copyOf(a, 2*n);
		int[] imap = shrinkX(b);
		if(!ok(imap.length-1, b)){
			out.println(-1);
			return;
		}
		int low = -1, high = imap.length;
		while(high - low > 1){
			int h = high+low>>1;
			if(ok(h, b)){
				high = h;
			}else{
				low = h;
			}
		}
		out.println(imap[high]);
	}

	boolean ok(int h, int[] b)
	{
		int n = b.length/2;
		DJSet ds = new DJSet(2*n);
		for(int i = 0;i < n;i++){
			if(b[2*i] > h)return false;
			if(b[2*i+1] > h){
				if(++ds.cycle[ds.root(b[2*i])] >= 2)return false;
			}else{
				if(ds.union(b[2*i], b[2*i+1])){
					if(++ds.cycle[ds.root(b[2*i])] >= 2)return false;
				}else{
					if(ds.cycle[ds.root(b[2*i])] >= 2)return false;
				}
			}
		}
		return true;
	}

	public static class DJSet {
		public int[] upper;
		public int[] cycle;

		public DJSet(int n) {
			upper = new int[n];
			Arrays.fill(upper, -1);
			cycle = new int[n];
		}

		public int root(int x) {
			return upper[x] < 0 ? x : (upper[x] = root(upper[x]));
		}

		public boolean equiv(int x, int y) {
			return root(x) == root(y);
		}

		public boolean union(int x, int y) {
			x = root(x);
			y = root(y);
			if (x != y) {
				if (upper[y] < upper[x]) {
					int d = x;
					x = y;
					y = d;
				}
				upper[x] += upper[y];
				upper[y] = x;

				cycle[x] += cycle[y];
			}
			return x == y;
		}

		public int count() {
			int ct = 0;
			for (int u : upper)
				if (u < 0)
					ct++;
			return ct;
		}
	}


	public static int[] shrinkX(int[] a) {
		int n = a.length;
		long[] b = new long[n];
		for (int i = 0; i < n; i++)
			b[i] = (long) a[i] << 32 | i;
		Arrays.sort(b);
		int[] ret = new int[n];
		int p = 0;
		ret[0] = (int) (b[0] >> 32);
		for (int i = 0; i < n; i++) {
			if (i > 0 && (b[i] ^ b[i - 1]) >> 32 != 0) {
				p++;
				ret[p] = (int) (b[i] >> 32);
			}
			a[(int) b[i]] = p;
		}
		return Arrays.copyOf(ret, p + 1);
	}


