            out.println("NO");
            return;
        }
        boolean isPossible = false;
        for(int i=0;i<n;i++){
            if(left[i]+right[i]==0){
                isPossible = true;
                break;
            }
        }
        if(!isPossible){
            out.println("NO");
            return;
        }
        int[] res = new int[n];
        for(int i=0;i<n;i++){
            res[i] = n-left[i]-right[i];
        }
