            int lcount = 0, rcount = 0;
            for(int j=i+1;j<n;j++){
                if(res[i]<res[j])rcount++;
            }
            for(int j=i-1;j>=0;j--){
                if(res[i]<res[j])lcount++;
            }
            if(left[i]!=lcount || right[i]!=rcount){
                // System.out.println("__"+ i);
