        for (int i = 0; i < n; i++) {

            if (map.containsKey(arr[i])) map.get(arr[i]).add(new Pair(0, i));
            else {
                List<Pair> l = new ArrayList<>();
                l.add(new Pair(0, i));
                map.put(arr[i], l);
            }

            for (int j = 1; j <= i; j++) {
                int ss = arr[i] - arr[j - 1];
                if (map.containsKey(ss)) map.get(ss).add(new Pair(j, i));
                else {
                    List<Pair> l = new ArrayList<>();
                    l.add(new Pair(j, i));
                    map.put(ss, l);
                }
            }
