    public static int overlap(List<P> listOfPair) {
        /*List<P> sortedList = listOfPair.stream()
                .sorted((pair1, pair2) -> pair1.getB().compareTo(pair2.getB()))
                .collect(Collectors.toList());*/
        List<P> sortedList = listOfPair;

