            for (int i = 0; i < n; i++) {
                a[i] = in.nextInt();
            }

            HashMap<Integer, Stack<Interval>> map = new HashMap<>();
            for (int i = 0; i < n; i++) {
                int sum = 0;
                for (int j = i; j < n; j++) {
                    sum += a[j];
