                        if (dp[i] < 1 + dp[ll]) {
                            dp[i] = Math.max(dp[i], 1 + dp[ll]);
                            taken[i] = true;
                            nextPos[i] = ll;
                        }
                    }
                }

                if (dp[0] > ans) {
                    ans = dp[0];
                    answer = intervals;
                    ansNextPos = nextPos;
                    ansTaken = taken;
                }
            }


            out.println(ans);
            int cur = 0;
            while (cur != -1) {
                if (ansTaken[cur]) {
                    out.println(answer.get(cur));
                }
                cur = ansNextPos[cur];
            }
        }

        out.close();
    }

