    static class FastReader {
	private byte[] buf = new byte[65536];
	private int ind = 0;
	private int maxInd = -1;
	private InputStream is = null;
	private boolean eof = false;
	private boolean lastCharRead = false;

	public FastReader(InputStream is) {
	    this.is = is;
	}

	public String readNextToken(boolean endOfLine) {
	    try {
		StringBuilder sb = new StringBuilder();
		boolean found = false;
		while (true) {
		    if (lastCharRead) {
			return null;
		    } else if (ind > maxInd) {
			if (eof) {
			    lastCharRead = true;
			} else {
			    fillBuffer();
			}
		    }
		    byte b = '\n';
		    if (!lastCharRead) {
			b = buf[ind++];
		    }

		    if (b == '\r') {
			// ignore
		    } else if ((b == '\n' && endOfLine) || (Character.isWhitespace(b) && !endOfLine)) {
			if (found) {
			    break;
			}
		    } else {
			sb.append((char) b);
			found = true;
		    }
		}
		return sb.toString();
	    } catch (Exception ex) {
		throw new RuntimeException(ex);
	    }
	}

	private void fillBuffer() {
	    try {
		int read = is.read(buf, 0, buf.length);
		if (read < buf.length) {
		    eof = true;
		}
		ind = 0;
		maxInd = read - 1;
	    } catch (Exception ex) {
		throw new RuntimeException(ex);
	    }
	}
    }

    public static class LST {
	public long[][] set;
	public int n;

	public LST(int n) {
	    this.n = n;
	    int d = 1;
	    for (int m = n; m > 1; m >>>= 6, d++)
		;

	    set = new long[d][];
	    for (int i = 0, m = n >>> 6; i < d; i++, m >>>= 6) {
		set[i] = new long[m + 1];
	    }
	}

	// [0,r)
	public LST setRange(int r) {
	    for (int i = 0; i < set.length; i++, r = r + 63 >>> 6) {
		for (int j = 0; j < r >>> 6; j++) {
		    set[i][j] = -1L;
		}
		if ((r & 63) != 0)
		    set[i][r >>> 6] |= (1L << r) - 1;
	    }
	    return this;
	}

	// [0,r)
	public LST unsetRange(int r) {
	    if (r >= 0) {
		for (int i = 0; i < set.length; i++, r = r + 63 >>> 6) {
		    for (int j = 0; j < r + 63 >>> 6; j++) {
			set[i][j] = 0;
		    }
		    if ((r & 63) != 0)
			set[i][r >>> 6] &= ~((1L << r) - 1);
		}
	    }
	    return this;
	}

	public LST set(int pos) {
	    if (pos >= 0 && pos < n) {
		for (int i = 0; i < set.length; i++, pos >>>= 6) {
		    set[i][pos >>> 6] |= 1L << pos;
		}
	    }
	    return this;
	}

	public LST unset(int pos) {
	    if (pos >= 0 && pos < n) {
		for (int i = 0; i < set.length && (i == 0 || set[i - 1][pos] == 0L); i++, pos >>>= 6) {
		    set[i][pos >>> 6] &= ~(1L << pos);
		}
	    }
	    return this;
	}

	public boolean get(int pos) {
	    return pos >= 0 && pos < n && set[0][pos >>> 6] << ~pos < 0;
	}

	public LST toggle(int pos) {
	    return get(pos) ? unset(pos) : set(pos);
	}

	public int prev(int pos) {
	    for (int i = 0; i < set.length && pos >= 0; i++, pos >>>= 6, pos--) {
		int pre = prev(set[i][pos >>> 6], pos & 63);
		if (pre != -1) {
		    pos = pos >>> 6 << 6 | pre;
		    while (i > 0)
			pos = pos << 6 | 63 - Long.numberOfLeadingZeros(set[--i][pos]);
		    return pos;
		}
	    }
	    return -1;
	}

	public int next(int pos) {
	    for (int i = 0; i < set.length && pos >>> 6 < set[i].length; i++, pos >>>= 6, pos++) {
		int nex = next(set[i][pos >>> 6], pos & 63);
		if (nex != -1) {
		    pos = pos >>> 6 << 6 | nex;
		    while (i > 0)
			pos = pos << 6 | Long.numberOfTrailingZeros(set[--i][pos]);
		    return pos;
		}
	    }
	    return -1;
	}

	private static int prev(long set, int n) {
	    long h = set << ~n;
	    if (h == 0L)
		return -1;
	    return -Long.numberOfLeadingZeros(h) + n;
	}

	private static int next(long set, int n) {
	    long h = set >>> n;
	    if (h == 0L)
		return -1;
	    return Long.numberOfTrailingZeros(h) + n;
	}

	@Override
	public String toString() {
	    List<Integer> list = new ArrayList<Integer>();
	    for (int pos = next(0); pos != -1; pos = next(pos + 1)) {
		list.add(pos);
	    }
	    return list.toString();
	}
    }
}

import java.util.*;

public class TaskF {
    public static void main(String[] args) {
        Scanner in = new Scanner(System.in);

        int n = in.nextInt();
        int[] a = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            a[i] = in.nextInt();
        }

        int[] prefixSum = new int[n + 1];
        prefixSum[0] = 0;
        for (int i = 1; i <= n; i++) {
            prefixSum[i] = prefixSum[i - 1] + a[i];
        }

        Map<Integer, List<Segment>> sumToSegments = new HashMap<>();
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                int sum = prefixSum[j] - prefixSum[i - 1];
                sumToSegments
                        .computeIfAbsent(sum, $ -> new ArrayList<>())
                        .add(Segment.make(i, j));
            }
        }

        List<Segment> bestSegments = null;
        for (int sum : sumToSegments.keySet()) {
            List<Segment> segments = sumToSegments.get(sum);
            int size = segments.size();

            int[] f = new int[size];
            int[] next = new int[size];
            boolean[] take = new boolean[size];

            f[size - 1] = 1;
            next[size - 1] = -1;
            take[size - 1] = true;
            int bestStartIndex = size - 1;

            for (int i = size - 2; i >= 0; i--) {
                int nextIndex;

                if (segments.get(i).q >= segments.get(size - 1).p) {
                    nextIndex = -1;
                } else {
                    int L = i + 1;
                    int R = size - 1;
                    while (L < R) {
                        int M = (L + R) / 2;
                        if (segments.get(i).q >= segments.get(M).p) { /* intersection */
                            L = M + 1;
                        } else {
                            R = M;
                        }
                    }
                    nextIndex = L;
                }

                f[i] = 1 + ((nextIndex == -1) ? 0 : f[nextIndex]);
                next[i] = nextIndex;
                take[i] = true;

                if (f[i + 1] > f[i]) {
                    take[i] = false;
                    f[i] = f[i + 1];
                    next[i] = i + 1;
                }

                if (bestStartIndex == -1 || f[i] > f[bestStartIndex]) {
                    bestStartIndex = i;
                }
            }

            // recover segment set
            List<Segment> maxForSum = new ArrayList<>();
            int index = bestStartIndex;
            do {
                if (take[index]) {
                    maxForSum.add(segments.get(index));
                }
                index = next[index];
            } while (index != -1);

            if (bestSegments == null || maxForSum.size() > bestSegments.size()) {
                bestSegments = maxForSum;
            }
        }

        System.out.println(bestSegments.size());
        for (Segment segment : bestSegments) {
            System.out.printf("%s %s%n", segment.p, segment.q);
        }

        in.close();
    }

    private static class Segment {
        public final int p;
        public final int q;

        private Segment(int p, int q) {
            this.p = p;
            this.q = q;
        }

        public static Segment make(int p, int q) {
            return new Segment(p, q);
        }
    }
}

