        char[] temp1 = new char[(int) 2e5 + 3];
        char[] temp2 = new char[(int) 2e5 + 3];
        char[] temp3 = new char[(int) 2e5 + 3];
        for (int i = 0; i < (int) 2e5 + 3; i++) {
            if (i % 3 == 0) temp1[i] = 'R';
            if (i % 3 == 1) temp1[i] = 'G';
            if (i % 3 == 2) temp1[i] = 'B';
            if (i % 3 == 0) temp2[i] = 'G';
            if (i % 3 == 1) temp2[i] = 'B';
            if (i % 3 == 2) temp2[i] = 'R';
            if (i % 3 == 0) temp3[i] = 'B';
            if (i % 3 == 1) temp3[i] = 'R';
            if (i % 3 == 2) temp3[i] = 'G';
        }

        while (q-- > 0) {
