            int[] dp1 = new int[n];
            int[] dp2 = new int[n];
            int[] dp3 = new int[n];
            for (int i = 0; i < n; i++) {
                if (str.charAt(i) != temp1[i]) dp1[i]++;
                if (str.charAt(i) != temp2[i]) dp2[i]++;
                if (str.charAt(i) != temp3[i]) dp3[i]++;
            }
            for (int i = 1; i < n; i++) {
                dp1[i] += dp1[i-1];
                dp2[i] += dp2[i-1];
                dp3[i] += dp3[i-1];
            }
