            for (int i = k; i < n; i++) {
              //  o.println(dp1[i-k] + " " + dp2[i-k] + " " + dp3[i-k]);
                ans = Math.min(ans, dp1[i] - dp1[i-k]);
                ans = Math.min(ans, dp2[i] -  dp2[i-k]);
                ans = Math.min(ans, dp3[i] - dp3[i-k]);
            }
            o.println(ans);
        }
        o.close();
        return;
