    static class TaskA {
        public void solve(int testNumber, InputReader in, OutputWriter out) {
            int n = in.readInt();
            int[] a = in.readIntArray(n);
            ArrayUtils.sort(a);
            boolean[] done = new boolean[n];
            int answer = 0;
            for (int i = 0; i < n; i++) {
