    static class APaintTheNumbers {
        public void solve(int testNumber, ScanReader in, PrintWriter out) {
            int n = in.scanInt();
            int arr[] = new int[n];
            in.scanInt(arr);
            CodeX.sort(arr);
            int ans = 0;
            boolean vissited[] = new boolean[n];
            for (int i = 0; i < n; i++) {
                if (!vissited[i]) {
                    ans++;
                    for (int j = 0; j < n; j++) {
