    boolean[] vis = new boolean[n];
    int nColours = 0;
    int nVis = 0;
    int index = 0;
    while (nVis<n) {
      while (index<n && nVis<n) {
        if (vis[index]) {
          index++;
          continue;
        }
        int val = arr[index];
        nColours++;
        while (index<n && nVis<n) {
          if (vis[index]) {
            index++;
            continue;
          }
          if (arr[index]%val==0) {
            vis[index] = true;
            nVis++;
          }
          index++;
        }
        index = 0;
      }
    }
    System.out.println(nColours);

  }
