                    list.add(n);
                } else {
                    for (int j = list.size() - 1; j >= 0; j--) {
                        if (list.get(j) == n - 1) {
                            list.set(j, n);
                            break;
                        }
                        list.remove(j);
                    }
                }
                for (int j = 0; j < list.size(); j++) {
                    System.out.print(list.get(j) + (j == list.size() - 1 ? "\n" : "."));
                }
            }
        }
    }
}

