    static class TaskC {
        public void solve(int testNumber, InputReader in, OutputWriter out) {
            int tests = in.nextInt();

            for (int t = 0; t < tests; t++) {
                int numLines = in.nextInt();
                // greedy, maintain stack, keep stack as big as possible
                int stackIdx = -1;
                int[] stack = new int[10000];
                String prev = "";
                for (int x = 0; x < numLines; x++) {
                    int depth = 0;
                    int next = in.nextInt();
                    boolean found = false;
                    for (int i = stackIdx; i >= 0; i--) {
                        if (next == stack[i] + 1) {
                            depth = i;
                            found = true;
                            break;
                        }
                    }
                    if (found == true) {
                        stackIdx = depth;
                        stack[depth] = next;
                        for (int i = 0; i <= depth; i++) {
                            if (i != 0) {
                                out.print(".");
                            }
                            out.print(stack[i]);
                        }
                        out.println();

                    } else if (next == 1) {
                        stackIdx++;
                        stack[stackIdx] = 1;
                        for (int i = 0; i <= stackIdx; i++) {
                            if (i != 0) {
                                out.print(".");
                            }
                            out.print(stack[i]);
                        }
                        out.println();

                    } else {
                        // start a new one
                        stackIdx = 0;
                        stack[0] = next;
                        out.println(next);
                    }


                }
            }
        }

    }

