    void solve() {
        int n = sc.nextInt();
        int[] a = sc.nextArray(n);

        int[] ps = new int[n];
        int[] q = new int[n];
        int[] qs = new int[n];
        int nq = 0;
        for (int i = 1; i < n; i++) {
            if (a[i] == 1) {
                qs[nq] = i - 1;
                q[nq++] = a[i - 1] + 1;
                ps[i] = i - 1;
            } else {
                if (a[i] == a[i - 1] + 1) {
                    qs[nq] = i - 1;
                    q[nq++] = 1;
                    ps[i] = i - 1;
                } else {
                    for (int j = nq - 1; j >= 0; j--) {
                        if (a[i] == q[j]) {
                            ps[i] = qs[j];
                            nq = j;
                            break;
                        }
                    }
                }
            }
        }

        int[] parents = ps;
        String[] strs = new String[n];
        strs[0] = "1";
        System.out.println(strs[0]);
        for (int i = 1; i < n; i++) {
            String p = strs[parents[i]];
            if (a[i] == 1) {
                strs[i] = p + ".1";
            } else {
                int lastDot = p.lastIndexOf(".");
                if (lastDot == -1) {
                    strs[i] = a[i] + "";
                } else {
                    strs[i] = p.substring(0, lastDot) + "." + a[i];
                }
            }
            System.out.println(strs[i]);
        }
    }

