		lis = new ArrayList<Integer>();
		for(int i = 0; i<n; i++)lis.add(sc.nextInt());
		Deque<Integer> q = new LinkedList<Integer>();
		for(int i = 0; i<n; i++) {
			if(i == 0) {
				q.add(1);
			}
			else {
				int val = lis.get(i);
				if(val == 1)q.add(1);
				else {
					while(q.peekLast() != val-1)q.pollLast();
					q.pollLast();
					q.add(val);
				}
			}
			int size = q.size();
			for(int e : q) {
				if(size == 1)System.out.print(e);
				else System.out.print(e+".");
				size--;
			}
			System.out.println();
		}

