            done = false;
            n = readInt();
            a = new int[n];
            prefixes = new int[n][];
            prefixes[0] = new int[0];
            for (int i = 0; i < n; i++) {
                a[i] = readInt();
            }
            int[] levels = new int[] {1};
            find(levels, 1);

            for (int i = 0; i < n; i++) {
                for (int j = 0; j < prefixes[i].length - 1; j++) {
                    out.print(prefixes[i][j] + ".");
                }
                out.println(a[i]);
            }


        }
    }
    int[] a;
    int n;
    boolean done;
    int[][] prefixes;

    void find(int[] levels, int position) {
        if (position == n) {
            done = true;
            return;
        }

        int value = a[position];
        if (value == 1) {
            int[] newlevels = Arrays.copyOf(levels, levels.length + 1);
            newlevels[levels.length] = 1;
            prefixes[position] = newlevels;
            find(newlevels, position + 1);
        }
        for (int i = levels.length - 1; i >= 0; i--) {
            if (value == levels[i] + 1) {

                int[] newlevels = Arrays.copyOf(levels, i + 1);
                newlevels[i]++;
                prefixes[position] = newlevels;
                find(newlevels, position + 1);
                if (done) {
                    return;
                }

                prefixes[position] = null;
            }
        }
    }


