    static class Node {
        int v, id;
        List<Node> child;

        Node(int v, int id) {
            this.v = v;
            this.id = id;
            child = new ArrayList<>();
        }
    }

    static String[] ans;
    static void solve(int testCnt) {
        for (int testNumber = 0; testNumber < testCnt; testNumber++) {
            int n = in.nextInt();
            int[] a = in.nextIntArrayPrimitive(n);
            ans = new String[n];
//            Node root = new Node(a[0], 0);
//            for(int i = 1; i < n; i++) {
//                insert(root, a[i], i);
//            }
//            dfs(root, new StringBuilder());
//            for(int i = 0; i < n; i++) {
//                out.println(ans[i]);
//            }
            ArrayDeque<Integer> q = new ArrayDeque<>();
            q.addLast(a[0]);
            for(int i = 1; i < n; i++) {
                printBuffer(q);
                if(a[i] == 1) {
                    q.addLast(a[i]);
                }
                else {
                    while(q.size() > 0 && q.peekLast() + 1 != a[i]) {
                        q.removeLast();
                    }
                    if(q.size() > 0) {
                        q.removeLast();
                    }
                    q.add(a[i]);
                }
            }
            printBuffer(q);
        }
        out.close();
    }

    static void printBuffer(ArrayDeque<Integer> q) {
        int sz = q.size();
        StringBuilder buffer = new StringBuilder();
        for(int j = 0; j < sz; j++) {
            int v = q.removeFirst();
            buffer.append(v);
            buffer.append(".");
            q.addLast(v);
        }
        buffer.deleteCharAt(buffer.length() - 1);
        out.println(buffer);
    }

    static void insert(Node root, int v, int idx) {
        ArrayDeque<Node> q = new ArrayDeque<>();
        q.addLast(root);
        while(q.size() > 0) {
            Node curr = q.removeFirst();
            if(curr.child.size() + 1 == v) {
                curr.child.add(new Node(v, idx));
                break;
            }
            else {
                for(Node next : curr.child) {
                    q.addLast(next);
                }
            }
        }
    }

    static void dfs(Node curr, StringBuilder buffer) {
        if(buffer.length() > 0) {
            buffer.append("." + curr.v);
        }
        else {
            buffer.append(curr.v);
        }
        ans[curr.id] = buffer.toString();
        for(Node next : curr.child) {
            dfs(next, new StringBuilder(buffer));
        }
    }

