public class C {
	private static BufferedReader br;

	public static void main(String[] args) throws IOException {
		br = new BufferedReader(new InputStreamReader(System.in));
		int t = Integer.parseInt(br.readLine());
		for (int i = 0; i < t; i++) {
			solve();
		}
		br.close();
	}

	private static void solve() throws IOException {
		int n = Integer.parseInt(br.readLine());
		int[] vals = new int[n];
		for (int i = 0; i < n; i++) {
			vals[i] = Integer.parseInt(br.readLine());
		}

		List<Integer> currtree = new ArrayList<Integer>();
		StringBuilder sb = new StringBuilder();
		for (int x : vals) {
			if (x == 1) {
				currtree.add(1);
			} else {
				int i = currtree.size() - 1;
				while (currtree.remove(i) != x-1) {
					i--;
					// inf loop if invalid
				}

				currtree.add(x);
			}

			appJoin(sb, currtree);
		}

		System.out.print(sb);
	}

	private static void appJoin(StringBuilder sb, List<Integer> vals) {
		sb.append(vals.get(0));
		for (int i = 1; i < vals.size(); i++) {
			sb.append("." + vals.get(i));
		}
		sb.append("\n");
	}
}

