  public static void main(String[] args) {
    C driver = new C();
    try {
      driver.solve();
    } finally {
      driver.close();
    }
  }

  public final PrintWriter out = new PrintWriter(new BufferedOutputStream(System.out));

  public final FastScanner in = FastScanner.INSTANCE;

  public void solve() {
    int tt = in.nextInt();
    while (tt-- > 0) {
      solveOne();
    }
  }

  protected void close() {
    out.close();
  }

  public void solveOne() {
    int n = in.nextInt();
    int[] a = in.nextArray(n);
    List<Integer> state = new ArrayList<>();
    // state.add(1);
    for (int i = 0; i < n; i++) {
      if (state.isEmpty()) {
        state.add(1);
      } else {
        int sz = state.size();
        int last = state.get(sz - 1);
        if (a[i] == 1) {
          state.add(1);
        } else if (a[i] == last + 1) {
          state.set(sz - 1, last + 1);
        } else {
          // boolean set = false;
          while (sz > 0) {
            last = state.get(sz - 1);
            if (a[i] == last + 1) {
              state.set(sz - 1, last + 1);
              // set = true;
              break;
            } else {
              state.remove(sz - 1);
              sz--;
            }
          }
        }
      }
      output(state);
    }
  }

  private void output(List<Integer> state) {
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < state.size(); i++) {
      if (i > 0) {
        sb.append(".");
      }
      sb.append(state.get(i));
    }
    out.println(sb);
  }

