			for (int i = 0; i < n; i++)
				a[i] = nextInt();
			return a;
		}

		int[] nextIntArrayOne(int n) {
			int[] a = new int[n + 1];
			for (int i = 1; i < n + 1; i++)
				a[i] = nextInt();
			return a;
		}

		long[] nextLongArray(int n) {
			long[] a = new long[n];
			for (int i = 0; i < n; i++)
				a[i] = nextLong();
			return a;
		}

		long[] nextLongArrayOne(int n) {
			long[] a = new long[n + 1];
			for (int i = 1; i < n + 1; i++)
				a[i] = nextLong();
			return a;
		}

		long nextLong() {
