				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}

	public static void main(String[] args) {
		FastReader s = new FastReader();
		StringBuilder str = new StringBuilder();

		int t = s.nextInt();

		while (t-- > 0) {
			int n = s.nextInt();

			int pre = s.nextInt();

			str.append(pre +"\n");
			LinkedList<Integer> list = new LinkedList<>();
			list.add(pre);
			for(int i = 1; i < n; i++) {
				int cur = s.nextInt();

				if(cur == 1) {
					list.addLast(cur);
				}else if(cur == pre + 1) {
					list.removeLast();
					list.addLast(cur);
				}else {

					while(!list.isEmpty() && list.getLast() + 1 != cur) {
							list.removeLast();
					}

					if(!list.isEmpty()) {
						list.removeLast();
					}
					list.addLast(cur);
				}
				addAns(list, str);
				pre = cur;
			}

		}
		System.out.println(str);
	}

	private static void addAns(LinkedList<Integer> list, StringBuilder str) {
		int n = list.size();
		for(int i = 0; i < n - 1;i++) {
			str.append(list.get(i) +".");
		}

		str.append(list.get(n - 1) + "\n");
	}

}

