public class Main {
    private static FastScanner in;
    private static PrintWriter out;

    public static void main (String[] args) throws IOException {
        if (System.getProperty("ONLINE_JUDGE") == null) {
            in = new FastScanner(new FileInputStream("input.txt"));
            out = new PrintWriter("output.txt");
        } else {
            in = new FastScanner();
            out = new PrintWriter(System.out);
        }

        int nTest = 1;
        nTest = in.nextInt();
        for (int testcase = 1; testcase <= nTest; ++testcase) {
            solve();
        }
        out.flush();
    }

    static void solve () throws IOException {
        int n = in.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; ++i) {
            a[i] = in.nextInt();
        }
        ArrayDeque<Integer> stk = new ArrayDeque<>();
        for (int u : a) {
            if (u != 1) {
                while (!stk.isEmpty() && stk.peekFirst() != u - 1) {
                    stk.pop();
                }
                if (!stk.isEmpty()) {
                    stk.pop();
                }
            }
            stk.push(u);
            StringBuilder ans = new StringBuilder();
            for (int v : stk) {
                StringBuilder t = new StringBuilder();
                t.append(v);
                t.reverse();
                ans.append(t + ".");
            }
            ans.deleteCharAt(ans.length() - 1);
            ans.reverse();
            out.println(ans);
        }

    }

    // ----------------- SORT -------------------
    static void sort (int[] a) {
        ArrayList<Integer> arr = new ArrayList<>();
        for (int val : a) {
            arr.add(val);
        }
        Collections.sort(arr);
        for (int i = 0; i < a.length; ++i) {
            a[i] = arr.get(i);
        }
    }

    // --------------------- I/O ---------------------
    static class FastScanner {
        private static BufferedInputStream bin;
        final private int N = 1 << 13;
        private byte[] buf;
        private int ptr, siz;

        FastScanner () throws IOException {
            bin = new BufferedInputStream(System.in);
            buf = new byte[N];
            ptr = siz = 0;
        }

        FastScanner (FileInputStream in) throws IOException {
            bin = new BufferedInputStream(in);
            buf = new byte[N];
            ptr = siz = 0;
        }

        private void fill () throws IOException {
            siz = bin.read(buf, 0, N);
            if (siz == -1) {
                buf[0] = -1;
            }
        }

        private byte read () throws IOException {
            if (ptr == siz) {
                fill();
                ptr = 0;
            }
            return buf[ptr++];
        }

        private boolean isWhiteSpace (byte c) {
            return c == ' ' || c == '\n' || c == '\t' || c == '\r';
        }

        public String nextLine () throws IOException {
            final int maxLength = 1000 + 5;
            byte[] s = new byte[maxLength];
            byte c = read();
            int len = 0;
            while (isWhiteSpace(c)) {
                c = read();
            }
            for (; c != -1 && c != '\n' && c != '\r'; c = read()) {
                s[len++] = c;
            }
            return new String(s, 0, len);
        }

        public int nextInt () throws IOException {
            int res = 0;
            byte c = read();
            while (isWhiteSpace(c)) {
                c = read();
            }
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = read();
            }
            for (; c >= '0' && c <= '9'; c = read()) {
                res = res * 10 + c - '0';
            }
            return neg ? -res : res;
        }

        public long nextLong () throws IOException {
            long res = 0;
            byte c = read();
            while (isWhiteSpace(c)) {
                c = read();
            }
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = read();
            }
            for (; c >= '0' && c <= '9'; c = read()) {
                res = res * 10 + c - '0';
            }
            return neg ? -res : res;
        }

        public double nextDouble () throws IOException {
            double res = 0, div = 1;
            byte c = read();
            while (isWhiteSpace(c)) {
                c = read();
            }
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = read();
            }
            for (; c >= '0' && c <= '9'; c = read()) {
                res = res * 10 + c - '0';
            }
            if (c == '.') {
                for (c = read(); c >= '0' && c <= '9'; c = read()) {
                    res += (c - '0') / div;
                    div *= 10;
                }
            }
            return neg ? -res : res;
        }
    }
}

import java.util.*;
import java.io.*;

public class Solution {

    public static Stack<Integer> s = new Stack<>();

    public static StringBuilder stackToString() {
        StringBuilder sb = new StringBuilder();
        Iterator<Integer> it = s.iterator();
        while (it.hasNext()) {
            sb.append(it.next());
            sb.append(it.hasNext() ? "." : "\n");
        }
        return sb;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int ntc = Integer.parseInt(br.readLine());
        for (int tc = 1; tc <= ntc; tc++) {
            s.clear();
            s.push(1);
            out.append(stackToString());
            int n = Integer.parseInt(br.readLine());
            br.readLine();  // first one gets discarded
            for (int i = 0; i < n-1; i++) {
                int x = Integer.parseInt(br.readLine());
                if (x == 1) s.push(x);
                else if (x == s.peek()+1) {
                    s.pop();
                    s.push(x);
                }
                else {
                    while (s.pop() != x-1);
                    s.push(x);
                }
                out.append(stackToString());
            }
        }
        System.out.print(out);
    }
}

