public class C {
    static class FastScanner {
        public BufferedReader reader;
        public StringTokenizer tokenizer;

        public FastScanner() {
            reader = new BufferedReader(new InputStreamReader(System.in), 32768);
            tokenizer = null;
        }

        public String next() {
            while (tokenizer == null || !tokenizer.hasMoreTokens()) {
                try {
                    tokenizer = new StringTokenizer(reader.readLine());
                } catch (IOException e) {
                    throw new RuntimeException(e);
                }
            }
            return tokenizer.nextToken();
        }

        public int nextInt() {
            return Integer.parseInt(next());
        }

        public long nextLong() {
            return Long.parseLong(next());
        }

        public double nextDouble() {
            return Double.parseDouble(next());
        }

        public String nextLine() {
            try {
                return reader.readLine();
            } catch (IOException e) {
                throw new RuntimeException(e);
            }
        }

        public int[] readIntArray(int n){
            int[] arr=new int[n];
            for(int i=0;i<n;i++){
                arr[i]=nextInt();
            }
            return arr;
        }

        public long[] readLongArray(int n){
            long[] arr=new long[n];
            for(int i=0;i<n;i++){
                arr[i]=nextLong();
            }
            return arr;
        }
    }
    public static void main(String args[]) throws Exception {
        FastScanner sc = new FastScanner();
        int T = 1;
        T = sc.nextInt();
        PrintWriter pw = new PrintWriter(System.out);
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            solve(sc, pw, sb);
        }
//        pw.print(sb);
        pw.close();
    }

    public static void solve(FastScanner sc, PrintWriter pw, StringBuilder sb) throws Exception {
        int n=sc.nextInt();
        int[] arr=sc.readIntArray(n);
        int[] stk = new int[2*n];
//        System.out.println("Arrays.toString(arr) = " + Arrays.toString(arr));
        int current_list=-1;
        for(int i=0;i<n;i++){
            if(arr[i]==1){
                // need to start a new list
                current_list++;
                stk[current_list]=1;
            }
            else{
                // find the most recent list that can accomodate this
//                System.out.println("i+\" \"+current_list = " + i+" "+current_list);
                while(current_list>=0){
                    if(stk[current_list]+1==arr[i]) break;
                    current_list--;
                }
//                System.out.println("current_list = " + current_list);
                stk[current_list]++;
            }
            StringBuilder ans=new StringBuilder();
            for(int j=0;j<=current_list;j++){
                ans.append(stk[j]);
                if(j+1<=current_list) ans.append(".");
            }
            pw.println(ans) ;
        }
    }
}

import java.util.ArrayList;
import java.util.Scanner;

public class C {
    public static void main(String[] args) {
        Scanner s = new Scanner(System.in);
        int lines = s.nextInt();

        s.nextLine();

        for (int i = 0; i < lines; i++) {
            int l = s.nextInt();

            int d[] = new int[l];

            s.nextLine();
            for (int j = 0; j < d.length; j++) {
                d[j] = s.nextInt();
            }

            solve(d);
        }
    }


    public static void solve(int data[]) {
        String erg = "";

        if (data.length == 0) return;

        ArrayList<Integer> line = new ArrayList<>();
        line.add(1);
        erg += "1";

        for (int i = 1; i < data.length; i++) {
            if (data[i] == 1) {
                line.add(1);
                erg += stringify(line);
            } else {
                for (int j = line.size() - 1; j >= 0; j--) {
                    if (line.get(j) + 1 == data[i]) {
                        line.set(j, data[i]);
                        erg += stringify(line);
                        j = -1;
                    } else {
                        line.remove(line.size() - 1);
                    }
                }
            }
        }

        System.out.println(erg);
    }

    public static String stringify(ArrayList<Integer> line) {
        String erg = "\n";

        for (int i: line) {
            erg += i + ".";
        }

        return erg.substring(0, erg.length() - 1);
    }
}

