	private static void add(Stack<Integer> stack, int num) {
		if(stack.isEmpty()) {
			stack.add(num);
			return;
		}
		if(num == 1) {
			stack.add(num);
			return;
		}
		while(!stack.isEmpty()) {
			int curr = stack.pop();
			if(curr + 1 == num) {
				break;
			}
		}
		stack.add(num);
	}


