		StringBuilder sb = new StringBuilder();
		while(!stack.isEmpty()) {
			stack2.add(stack.pop());
		}
		while(!stack2.isEmpty()) {
			int num = stack2.pop();
			if(stack2.isEmpty()) {
				sb.append(num+"");
			}
			else {
				sb.append(num + ".");
			}
			stack.add(num);
		}
		out.println(sb.toString());
