  static void solve() {
      int j=0;
      Stack<Integer> stack=new Stack<>();
      b[j]=a[0];
      str.append(a[0]).append("\n");
      stack.push(a[0]);
      for(int i=1;i<n;i++){
          if(a[i]==1){
              for(int k=0;k<=j;k++) str.append(b[k]).append(".");
              b[j+1]=1;
              str.append(1).append("\n");
              stack.push(1);
              j++;
          }else{
              for(int k=j;k>=0;k--){
                  if(a[i]==(b[k]+1)){
                      for(int p=0;p<k;p++) str.append(b[p]).append(".");
                      str.append(a[i]).append("\n");
                      stack.pop();
                      stack.push(a[i]);
                      b[k]=a[i];
                      j=k;
                      break;
                  }
                  stack.pop();
              }
          }
      }
  }

